# ISO 42001 Annex A defines a reference control set.
# The following maps the most operationally relevant controls
# to concrete GenAI implementations.

ANNEX_A_CONTROLS = {
    "A.2.2": {
        "title": "Roles, responsibilities and authorities",
        "genai_impl": (
            "Define and document: AI system owner (accountable), "
            "model steward (data/model quality), risk steward (2LoD), "
            "AI ethics officer. Publish in RACI matrix."
        ),
        "evidence": ["RACI matrix signed by CISO", "Role descriptions in HR system"],
    },
    "A.3.3": {
        "title": "AI risk assessment",
        "genai_impl": (
            "For each use case: assess likelihood and impact across individual, "
            "group, societal, and organisational dimensions before deployment."
        ),
        "evidence": ["ISO42001RiskAssessment record per use case", "Approval by risk committee"],
    },
    "A.4.2": {
        "title": "AI system impact assessment",
        "genai_impl": (
            "Conduct an AI Impact Assessment (analogous to DPIA) for high-risk use cases. "
            "Document intended use, foreseeable misuse, and affected populations."
        ),
        "evidence": ["Impact assessment document", "Sign-off by data protection officer"],
    },
    "A.6.1": {
        "title": "Data governance for AI",
        "genai_impl": (
            "Training data provenance documented; data quality checks automated in pipeline; "
            "data contracts in place with upstream providers."
        ),
        "evidence": ["Data contract catalogue", "Quality check run logs", "Provenance records"],
    },
    "A.6.2": {
        "title": "Data acquisition and collection",
        "genai_impl": (
            "Lawful basis for processing confirmed before data ingestion. "
            "PII minimised or pseudonymised before use in training."
        ),
        "evidence": ["Lawful basis register", "PII minimisation procedure", "Privacy review sign-off"],
    },
    "A.7.3": {
        "title": "AI system testing",
        "genai_impl": (
            "Pre-deployment test suite: functional, adversarial (red-team), "
            "fairness/bias evaluation, and performance benchmarks. "
            "All gates must pass before production deployment."
        ),
        "evidence": ["Test suite results", "Red-team report", "Bias evaluation report"],
    },
    "A.8.5": {
        "title": "Transparency and explainability",
        "genai_impl": (
            "Model card published for each production model. "
            "Users informed that output is AI-generated when required. "
            "Confidence scores surfaced for high-stakes outputs."
        ),
        "evidence": ["Model card document", "User disclosure notice in UI", "Confidence score log"],
    },
    "A.9.7": {
        "title": "Addressing AI system incidents",
        "genai_impl": (
            "AI-specific incident categories in the IR plan: hallucination at scale, "
            "safety failure, model regression, data breach via prompt. "
            "Post-incident review captures AI-specific root cause."
        ),
        "evidence": ["IR plan AI annex", "Incident log for audit period", "PIR records"],
    },
}

def check_annex_a_coverage(implemented_control_ids: set[str]) -> dict:
    """Returns coverage status for each Annex A control."""
    coverage = {}
    for ctrl_id, ctrl in ANNEX_A_CONTROLS.items():
        coverage[ctrl_id] = {
            "title": ctrl["title"],
            "implemented": ctrl_id in implemented_control_ids,
            "required_evidence": ctrl["evidence"],
        }
    total = len(coverage)
    covered = sum(1 for v in coverage.values() if v["implemented"])
    return {
        "coverage_pct": round(covered / total * 100, 1),
        "controls": coverage,
    }
